import React, { useState } from "react";
import "./Men.css";

import w1 from "../assets/women1.jpg";
import w2 from "../assets/women2.jpg";
import w3 from "../assets/women3.jpg";
import w4 from "../assets/women4.jpg";
import w5 from "../assets/women5.jpg";
import w6 from "../assets/women6.jpg";
import w7 from "../assets/women7.jpg";
import w8 from "../assets/women8.jpg";


const products = [
  { id: 1, name: "Women Casual Dress", price: 45, img: w1 },
  { id: 2, name: "Women Formal Dress", price: 65, img: w2 },
  { id: 3, name: "Women Top", price: 35, img: w3 },
  { id: 4, name: "Women Jacket", price: 80, img: w4 },
  { id: 5, name: "Women Jacket", price: 70, img: w4 },
  { id: 6, name: "Women Jacket", price: 80, img: w4 },
  { id: 7, name: "Women Jacket", price: 90, img: w4 },
  { id: 8, name: "Women Jacket", price: 80, img: w4 },
];

function Women() {
  const [qty, setQty] = useState({});

  const increase = (id) =>
    setQty({ ...qty, [id]: (qty[id] || 0) + 1 });

  const decrease = (id) =>
    setQty({ ...qty, [id]: Math.max((qty[id] || 0) - 1, 0) });

  return (
    <div className="men-page">
      <h2 className="men-title">Women Collection</h2>

      <div className="men-grid">
        {products.map((item) => (
          <div className="men-card" key={item.id}>
            <div className="men-img-box">
              <img src={item.img} alt={item.name} />
            </div>

            <div className="men-info">
              <h3>{item.name}</h3>
              <p className="price">${item.price}</p>

              <div className="qty-box">
                <button onClick={() => decrease(item.id)}>-</button>
                <span>{qty[item.id] || 0}</span>
                <button onClick={() => increase(item.id)}>+</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Women;
